cat << 'EOF' > test_enum_serializer.py
import enum
import re

class BaseSerializer:
    def __init__(self, value):
        self.value = value

def serializer_factory(value):
    class DummySerializer:
        def serialize(self):
            return repr(value), set()
    return DummySerializer()

class EnumSerializer(BaseSerializer):
    def serialize(self):
        enum_class = self.value.__class__
        module = enum_class.__module__
        v_string, v_imports = serializer_factory(self.value.value).serialize()
        imports = {"import %s" % module, *v_imports}

        if isinstance(self.value, enum.Flag):
            if self.value.name is not None and '|' not in self.value.name:
                return (
                    "%s.%s[%r]" % (module, enum_class.__qualname__, self.value.name),
                    imports,
                )

            if hasattr(enum, '_decompose'):
                members, uncovered = enum._decompose(enum_class, self.value.value)
                members = [m for m in members if m.name is not None]
                uncovered = self.value.value
                for m in members:
                    uncovered &= ~m.value
            else:
                members = list(self.value)
                uncovered = self.value.value
                for m in members:
                    uncovered &= ~m.value

            if not members and uncovered:
                return "%s.%s(%s)" % (module, enum_class.__qualname__, v_string), imports

            exprs = ["%s.%s[%r]" % (module, enum_class.__qualname__, m.name) for m in members]
            if uncovered:
                exprs.append("%s.%s(%s)" % (module, enum_class.__qualname__, uncovered))

            return " | ".join(exprs), imports

        return (
            "%s.%s[%r]" % (module, enum_class.__qualname__, self.value.name),
            imports,
        )

flags = re.UNICODE | re.IGNORECASE
print(EnumSerializer(flags).serialize())

class MyFlag(enum.IntFlag):
    A = 1
    B = 2

print(EnumSerializer(MyFlag.A | MyFlag.B | 4).serialize())
print(EnumSerializer(MyFlag(4)).serialize())
print(EnumSerializer(MyFlag.A).serialize())

